"use client";

import React, {
  createContext,
  useContext,
  useEffect,
  useId,
  useRef,
  useState,
  useCallback,
} from "react";
import { ArrowLeft, Check } from "lucide-react";
import { AnimatePresence, motion, type Variants } from "framer-motion";
import { cn } from "@/lib/utils";

// ─── Animation presets ──────────────────────────────────────────────────────
const PANEL_VARIANTS: Variants = {
  hidden: {
    opacity: 0,
    scale: 0.95,
    y: -4,
  },
  visible: {
    opacity: 1,
    scale: 1,
    y: 0,
    transition: {
      type: "spring",
      stiffness: 500,
      damping: 32,
      mass: 0.6,
      staggerChildren: 0.04,
    },
  },
  exit: {
    opacity: 0,
    scale: 0.97,
    y: -2,
    transition: { duration: 0.15, ease: "easeIn" },
  },
};

const CHILD_VARIANTS: Variants = {
  hidden: { opacity: 0, y: 6 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { type: "spring", stiffness: 400, damping: 28 },
  },
};

// ─── Context ────────────────────────────────────────────────────────────────
interface FloatingPanelContextType {
  isOpen: boolean;
  openPanel: () => void;
  closePanel: () => void;
  uniqueId: string;
  note: string;
  setNote: (note: string) => void;
  title: string;
  setTitle: (title: string) => void;
}

const FloatingPanelContext = createContext<FloatingPanelContextType | undefined>(
  undefined
);

function useFloatingPanel() {
  const context = useContext(FloatingPanelContext);
  if (!context) {
    throw new Error(
      "useFloatingPanel must be used within a FloatingPanelRoot"
    );
  }
  return context;
}

// ─── Root ───────────────────────────────────────────────────────────────────
interface FloatingPanelRootProps {
  children: React.ReactNode;
  className?: string;
}

export function FloatingPanelRoot({
  children,
  className,
}: FloatingPanelRootProps) {
  const uniqueId = useId();
  const [isOpen, setIsOpen] = useState(false);
  const [note, setNote] = useState("");
  const [title, setTitle] = useState("");

  const openPanel = useCallback(() => setIsOpen(true), []);
  const closePanel = useCallback(() => {
    setIsOpen(false);
    setNote("");
  }, []);

  return (
    <FloatingPanelContext.Provider
      value={{ isOpen, openPanel, closePanel, uniqueId, note, setNote, title, setTitle }}
    >
      <div className={cn("relative inline-block", className)}>
        {children}
      </div>
    </FloatingPanelContext.Provider>
  );
}

// ─── Trigger ────────────────────────────────────────────────────────────────
interface FloatingPanelTriggerProps {
  children: React.ReactNode;
  className?: string;
  title?: string;
}

export function FloatingPanelTrigger({
  children,
  className,
  title = "",
}: FloatingPanelTriggerProps) {
  const { openPanel, setTitle, isOpen } = useFloatingPanel();

  const handleClick = () => {
    setTitle(title);
    openPanel();
  };

  return (
    <motion.button
      className={cn(
        "relative flex h-10 items-center gap-2 rounded-xl border border-white/[0.1] bg-white/[0.05] px-4 text-sm font-semibold text-white backdrop-blur-sm transition-all duration-200",
        "hover:border-white/[0.2] hover:bg-white/[0.08] hover:shadow-[0_0_24px_-6px_rgba(79,143,255,0.3)]",
        isOpen && "border-white/[0.2] bg-white/[0.08]",
        className
      )}
      onClick={handleClick}
      whileTap={{ scale: 0.97 }}
      aria-haspopup="dialog"
      aria-expanded={isOpen}
    >
      {children}
    </motion.button>
  );
}

// ─── Content ────────────────────────────────────────────────────────────────
interface FloatingPanelContentProps {
  children: React.ReactNode;
  className?: string;
  align?: "left" | "center" | "right";
}

export function FloatingPanelContent({
  children,
  className,
  align = "left",
}: FloatingPanelContentProps) {
  const { isOpen, closePanel, uniqueId, title } = useFloatingPanel();
  const panelRef = useRef<HTMLDivElement>(null);

  // Click outside
  useEffect(() => {
    if (!isOpen) return;
    const handler = (e: MouseEvent) => {
      if (panelRef.current && !panelRef.current.contains(e.target as Node)) {
        closePanel();
      }
    };
    // Delay to avoid the trigger click from immediately closing
    const timer = setTimeout(() => {
      document.addEventListener("mousedown", handler);
    }, 10);
    return () => {
      clearTimeout(timer);
      document.removeEventListener("mousedown", handler);
    };
  }, [isOpen, closePanel]);

  // ESC
  useEffect(() => {
    if (!isOpen) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === "Escape") closePanel();
    };
    document.addEventListener("keydown", handler);
    return () => document.removeEventListener("keydown", handler);
  }, [isOpen, closePanel]);

  const alignClass =
    align === "center"
      ? "left-1/2 -translate-x-1/2"
      : align === "right"
        ? "right-0"
        : "left-0";

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          ref={panelRef}
          className={cn(
            "absolute top-full z-50 mt-2 w-[340px] origin-top overflow-hidden rounded-2xl border border-white/[0.1] bg-zinc-950/95 shadow-[0_16px_64px_-16px_rgba(0,0,0,0.7),0_0_0_1px_rgba(255,255,255,0.04)] backdrop-blur-2xl",
            alignClass,
            className
          )}
          variants={PANEL_VARIANTS}
          initial="hidden"
          animate="visible"
          exit="exit"
          role="dialog"
          aria-modal="true"
          aria-labelledby={`fp-title-${uniqueId}`}
        >
          {/* Gradient accent line */}
          <div className="h-[2px] bg-gradient-to-r from-blue-500 via-cyan-400 to-purple-500" />

          {/* Title bar */}
          {title && (
            <motion.div
              variants={CHILD_VARIANTS}
              className="flex items-center border-b border-white/[0.06] bg-white/[0.02] px-4 py-3"
            >
              <span
                className="text-sm font-semibold text-white"
                id={`fp-title-${uniqueId}`}
              >
                {title}
              </span>
            </motion.div>
          )}

          {children}
        </motion.div>
      )}
    </AnimatePresence>
  );
}

// ─── Form ───────────────────────────────────────────────────────────────────
interface FloatingPanelFormProps {
  children: React.ReactNode;
  onSubmit?: (note: string) => void;
  className?: string;
}

export function FloatingPanelForm({
  children,
  onSubmit,
  className,
}: FloatingPanelFormProps) {
  const { note, closePanel } = useFloatingPanel();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit?.(note);
    closePanel();
  };

  return (
    <form
      className={cn("flex h-full flex-col", className)}
      onSubmit={handleSubmit}
    >
      {children}
    </form>
  );
}

// ─── Label ──────────────────────────────────────────────────────────────────
interface FloatingPanelLabelProps {
  children: React.ReactNode;
  htmlFor: string;
  className?: string;
}

export function FloatingPanelLabel({
  children,
  htmlFor,
  className,
}: FloatingPanelLabelProps) {
  const { note } = useFloatingPanel();

  return (
    <motion.label
      htmlFor={htmlFor}
      variants={CHILD_VARIANTS}
      className={cn(
        "block px-4 pt-3 text-xs font-medium uppercase tracking-wider text-zinc-500 transition-opacity duration-200",
        note && "opacity-0",
        className
      )}
    >
      {children}
    </motion.label>
  );
}

// ─── Textarea ───────────────────────────────────────────────────────────────
interface FloatingPanelTextareaProps {
  className?: string;
  id?: string;
  placeholder?: string;
}

export function FloatingPanelTextarea({
  className,
  id,
  placeholder,
}: FloatingPanelTextareaProps) {
  const { note, setNote } = useFloatingPanel();
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // Reliable auto-focus
  useEffect(() => {
    const timer = setTimeout(() => textareaRef.current?.focus(), 50);
    return () => clearTimeout(timer);
  }, []);

  return (
    <motion.div variants={CHILD_VARIANTS}>
      <textarea
        ref={textareaRef}
        id={id}
        placeholder={placeholder}
        className={cn(
          "min-h-[100px] w-full resize-none bg-transparent px-4 py-3 text-sm text-white outline-none placeholder:text-zinc-600",
          className
        )}
        value={note}
        onChange={(e) => setNote(e.target.value)}
      />
    </motion.div>
  );
}

// ─── Header ─────────────────────────────────────────────────────────────────
interface FloatingPanelHeaderProps {
  children: React.ReactNode;
  className?: string;
}

export function FloatingPanelHeader({
  children,
  className,
}: FloatingPanelHeaderProps) {
  return (
    <motion.div
      variants={CHILD_VARIANTS}
      className={cn("px-4 py-3 text-sm font-semibold text-white", className)}
    >
      {children}
    </motion.div>
  );
}

// ─── Body ───────────────────────────────────────────────────────────────────
interface FloatingPanelBodyProps {
  children: React.ReactNode;
  className?: string;
}

export function FloatingPanelBody({
  children,
  className,
}: FloatingPanelBodyProps) {
  return (
    <motion.div variants={CHILD_VARIANTS} className={cn("p-2", className)}>
      {children}
    </motion.div>
  );
}

// ─── Footer ─────────────────────────────────────────────────────────────────
interface FloatingPanelFooterProps {
  children: React.ReactNode;
  className?: string;
}

export function FloatingPanelFooter({
  children,
  className,
}: FloatingPanelFooterProps) {
  return (
    <motion.div
      variants={CHILD_VARIANTS}
      className={cn(
        "flex items-center justify-between border-t border-white/[0.06] bg-white/[0.015] px-3 py-2.5",
        className
      )}
    >
      {children}
    </motion.div>
  );
}

// ─── Close Button ───────────────────────────────────────────────────────────
interface FloatingPanelCloseButtonProps {
  className?: string;
}

export function FloatingPanelCloseButton({
  className,
}: FloatingPanelCloseButtonProps) {
  const { closePanel } = useFloatingPanel();

  return (
    <button
      type="button"
      className={cn(
        "flex h-8 items-center gap-1.5 rounded-lg border border-white/[0.06] bg-white/[0.03] px-2.5 text-xs font-medium text-zinc-400 transition-all hover:border-white/[0.12] hover:bg-white/[0.06] hover:text-white",
        className
      )}
      onClick={closePanel}
      aria-label="Close panel"
    >
      <ArrowLeft className="h-3 w-3" />
      Back
    </button>
  );
}

// ─── Submit Button ──────────────────────────────────────────────────────────
interface FloatingPanelSubmitButtonProps {
  className?: string;
  children?: React.ReactNode;
}

export function FloatingPanelSubmitButton({
  className,
  children,
}: FloatingPanelSubmitButtonProps) {
  return (
    <button
      className={cn(
        "flex h-8 items-center gap-1.5 rounded-lg bg-gradient-to-r from-blue-500 to-cyan-500 px-3 text-xs font-semibold text-white shadow-[0_0_16px_-4px_rgba(59,130,246,0.4)] transition-all hover:shadow-[0_0_24px_-4px_rgba(59,130,246,0.6)] active:scale-[0.97]",
        className
      )}
      type="submit"
      aria-label="Submit"
    >
      {children || (
        <>
          <Check className="h-3 w-3" />
          Submit
        </>
      )}
    </button>
  );
}

// ─── Generic Button ─────────────────────────────────────────────────────────
interface FloatingPanelButtonProps {
  children: React.ReactNode;
  onClick?: () => void;
  className?: string;
}

export function FloatingPanelButton({
  children,
  onClick,
  className,
}: FloatingPanelButtonProps) {
  return (
    <button
      type="button"
      className={cn(
        "flex w-full items-center gap-2.5 rounded-lg px-3 py-2.5 text-left text-sm text-zinc-400 transition-all hover:bg-white/[0.06] hover:text-white active:scale-[0.98]",
        className
      )}
      onClick={onClick}
    >
      {children}
    </button>
  );
}
